import{_ as p,o as t,c as e,Q as o}from"./chunks/framework.1b6086f5.js";const A=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"doc/业务框架/DTM/ACID理论.md","filePath":"packages/doc/src/业务框架/DTM/ACID理论.md","lastUpdated":1702458087000}'),a={name:"doc/业务框架/DTM/ACID理论.md"},s=o("<p>事务具有 4 个属性：原子性、一致性、隔离性、持久性。这四个属性通常称为 ACID 特性。</p><ul><li>Atomicity（原子性）：一个事务中的所有操作，要么全部完成，要么全部不完成，不会结束在中间某个环节。事务在执行过程中发生错误，会被恢复到事务开始前的状态，就像这个事务从来没有执行过一样。</li><li>Consistency（一致性）：在事务开始之前和事务结束以后，数据库的完整性没有被破坏。完整性包括外键约束、应用定义的等约束不会被破坏。</li><li>Isolation（隔离性）：数据库允许多个并发事务同时对其数据进行读写和修改的能力，隔离性可以防止多个事务并发执行时由于交叉执行而导致数据的不一致。</li><li>Durability（持久性）：事务处理结束后，对数据的修改就是永久的，即便系统故障也不会丢失。</li></ul><p><strong>问题：</strong></p><p>一致性是指数据处于一种语义上的有意义且正确？？？的状态。</p><p>​ 一致性是对数据可见性的约束，保证在一个事务中的多次操作的数据中间状态？？？对其他事务不可见的。因为这些中间状态，是一个过渡状态，与事务的开始状态和事务的结束状态是不一致的。</p><p>2，举例：</p><p>举个例子，张三给李四转账100元。事务要做的是从张三账户上减掉100元，李四账户上加上100元。一致性的含义是其他事务要么看到张三还没有给李四转账的状态，要么张三已经成功转账给李四的状态，而对于张三少了100元，李四还没加上100元这个中间状态是不可见的。</p><p>那么反驳的声音来了：</p><p>要么转账操作全部成功，要么全部失败，这是原子性。从例子上看全部成功，那么一致性就是原子性的一部分咯，为什么还要单独说一致性和原子性？</p><p>你说的不对。在未提交读的隔离级别下是事务内部操作是可见的，明显违背了一致性，怎么解释？</p><p></p><p>二，一致性和原子性的区别</p><p>原子性和一致性的的侧重点不同：原子性关注状态，要么全部成功，要么全部失败，不存在部分成功的状态。</p><p>而一致性关注数据的可见性，中间状态的数据对外部不可见，只有最初状态和最终状态的数据对外可见</p><p>三，扩展</p><p>隔离性是多个事务的时候, 相互不能干扰，一致性是要保证操作前和操作后数据或者数据结构的一致性，而我提到的事务的一致性是关注数据的中间状态，也就是一致性需要监视中间状态的数据，如果有变化，即刻回滚</p>",16),_=[s];function i(c,n,r,l,d,D){return t(),e("div",null,_)}const T=p(a,[["render",i]]);export{A as __pageData,T as default};
